def solve(grid):
    import numpy as np
    from collections import deque
    from scipy import ndimage

    inp = np.array(grid)
    out = inp.copy()
    H, W = inp.shape

    # Find connected components of 1s
    mask = (inp == 1).astype(int)
    labeled, num = ndimage.label(mask)

    for comp in range(1, num + 1):
        comp_mask = (labeled == comp)

        # Detect holes: flood fill from boundary treating this component as walls
        passable = ~comp_mask
        visited = np.zeros((H, W), dtype=bool)
        queue = deque()

        for r in range(H):
            for c in [0, W - 1]:
                if passable[r, c] and not visited[r, c]:
                    visited[r, c] = True
                    queue.append((r, c))
        for c in range(W):
            for r in [0, H - 1]:
                if passable[r, c] and not visited[r, c]:
                    visited[r, c] = True
                    queue.append((r, c))

        while queue:
            r, c = queue.popleft()
            for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < H and 0 <= nc < W and not visited[nr, nc] and passable[nr, nc]:
                    visited[nr, nc] = True
                    queue.append((nr, nc))

        # Holes: not visited, not part of component
        hole_mask = np.zeros((H, W), dtype=bool)
        for r in range(H):
            for c in range(W):
                if not comp_mask[r, c] and not visited[r, c]:
                    hole_mask[r, c] = True

        has_holes = np.any(hole_mask)

        # Filled shape = component + holes
        filled = comp_mask | hole_mask

        if has_holes:
            # Recolor: 1s -> 8, holes -> 6
            out[comp_mask] = 8
            out[hole_mask] = 6
        # else: keep 1s as 1

        # Draw 8-connected border
        for r in range(H):
            for c in range(W):
